9	\begin{definition}
10	
11	\leanok
12	[Relative cotangent presheaf of a morphism]
13	  \label{def:relative_kaehler_presheaf}
14	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
15	  Let \(f \colon X \to S\) be a morphism of schemes. The presheaf-level inverse-image presheaf of rings \(f^{-1}_{\mathrm{psh}}\struct{S}\) on \(X\) (the left Kan extension of \(\struct{S}\) along \((\mathrm{Opens.map}\,f.\mathrm{base}).\mathrm{op}\), given on each open \(V \subseteq X\) by the colimit \(\mathrm{colim}_{W : \,f V \subseteq W \subseteq S}\,\struct{S}(W)\)) is paired with \(\struct{X}\) by the canonical adjunction-transpose \(f^{-1}_{\mathrm{psh}}\struct{S} \to \struct{X}\) of the comorphism \(f^{\sharp}\colon\struct{S}\to f_{*}\struct{X}\). Applying the presheaf-of-modules K\"ahler differential construction \(\mathrm{relativeDifferentials}'\) to this map of presheaves of commutative rings produces a presheaf of \(\struct{X}\)-modules on \(X\), the \emph{relative cotangent presheaf} \(\Omega_{X/S}\).
16	\end{definition}
17	
18	\begin{lemma}
19	
20	\leanok
21	[Sections of \(\Omega_{X/S}\) on an open]
22	  \label{lem:relative_kaehler_presheaf_obj}
23	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_obj_kaehler}
24	  
